// ======================= CONFIG — EDIT THESE ==========================
const SHARED_SECRET = 'REPLACE_WITH_YOUR_SHARED_SECRET'; // must match front end
const AI_MODEL = 'claude-sonnet-4.6';                    // TokenMix model id
// ======================================================================

const headers = $json.headers || {};
const body = $json.body || {};
const phase = Number(body.phase);

let valid = true, status = 200, code = '', message = '';

if (String(headers['x-shared-secret'] || '') !== SHARED_SECRET) {
  valid = false; status = 401; code = 'BAD_SECRET'; message = 'Unauthorized';
} else if (![1, 2, 3, 4].includes(phase)) {
  valid = false; status = 400; code = 'BAD_PHASE'; message = 'phase must be 1, 2, 3 or 4';
} else if (phase !== 1 && !(body.session_id && String(body.session_id).trim())) {
  valid = false; status = 400; code = 'NO_SESSION'; message = 'Missing session_id — start from Phase 1';
}

return { json: {
  valid: valid,
  status: status,
  code: code,
  error_message: message,
  phase: valid ? phase : 0,
  session_id: phase === 1 ? '' : String(body.session_id || ''),
  guest_name: String(body.guest_name || ''),
  inputs: body.inputs || {},
  ai_model: AI_MODEL
} };

const src = $('Build Prompt P1').first().json;
const j = $input.item.json || {};

let output = null;
let aiError = false;

try {
  // The OpenAI node output shape depends on the "Simplify Output" toggle —
  // handle raw, simplified, and content-block variants.
  let text = null;
  if (j.choices && j.choices[0] && j.choices[0].message) {
    text = j.choices[0].message.content;           // raw API response
  } else if (j.message && j.message.content != null) {
    text = j.message.content;                      // simplified output
  } else if (typeof j.content === 'string') {
    text = j.content;
  } else if (typeof j.text === 'string') {
    text = j.text;
  } else if (typeof j.output === 'string') {
    text = j.output;
  }
  if (Array.isArray(text)) {
    text = text.map(function (b) { return (b && (b.text || b.content)) || ''; }).join('');
  }
  if (!text) {
    throw new Error(j.error && j.error.message ? j.error.message : 'no content in response');
  }
  text = String(text).trim();
  if (text.indexOf('```') === 0) {
    text = text.replace(/^```[a-zA-Z]*\s*/, '').replace(/```\s*$/, '').trim();
  }
  output = JSON.parse(text);
} catch (e) {
  aiError = true;
}

const message = 'Diagnosis incomplete, please retry';
const envelopeOut = aiError
  ? { session_id: src.session_id, phase: src.phase, attempt_number: src.attempt_number, error: true, message: message }
  : { session_id: src.session_id, phase: src.phase, attempt_number: src.attempt_number, error: false, output: output };

return { json: {
  session_id: src.session_id,
  guest_name: src.guest_name,
  phase: src.phase,
  attempt_number: src.attempt_number,
  input_json: JSON.stringify(src.inputs || {}),
  output_json: JSON.stringify(aiError ? { error: true, message: message } : output),
  timestamp: new Date().toISOString(),
  envelope: envelopeOut
} };

const req = $('Validate Request').first().json;
const rows = $input.all().map(function (i) { return i.json; }).filter(function (r) { return r && r.session_id; });
const attempt = rows.filter(function (r) {
  return String(r.session_id) === String(req.session_id) && Number(r.phase) === 2;
}).length + 1;
const inp = req.inputs || {};
const S = function (v) { return typeof v === 'string' ? v : JSON.stringify(v, null, 2); };

const prompt_text = "ROLE
You are a positioning strategist. You convert a founder's operational
self-perception into a single, sharp executive-level statement of the
gap between how they're perceived and who they want to become.

CONTEXT
Input is the Phase 1 diagnosis plus two guest statements: what they're
currently known for, and what they want to be known for.
Reference pattern (do not copy content, only structure):
Input: "Carbon audits and compliance reports" -> "Strategic sustainability
transformation advisor"
Output: "You are positioned as a technician, while your ambition is to
operate as a board-level transformation advisor."

COMMAND
1. Name the current perceived role in 2-4 words (concrete, not flattering).
2. Name the desired role in 2-4 words (concrete, not aspirational fluff).
3. Label the gap type in 2-4 words (e.g. "tactical vs strategic authority").
4. Write ONE positioning gap statement using the exact pattern:
"You are positioned as [X], while your ambition is to operate as [Y]."
The statement must be quotable on screen — short, sharp, no qualifiers.

FORMAT
Return ONLY valid JSON, no markdown, no preamble:
{
"current_role": "...",
"desired_role": "...",
"gap_label": "...",
"gap_statement": "..."
}" + "

" + ('PHASE 1 DIAGNOSIS:' + String.fromCharCode(10) + S(inp.phase1_output || '(missing)') + String.fromCharCode(10) + String.fromCharCode(10)
  + 'CURRENT / DESIRED:' + String.fromCharCode(10) + S(inp.current_known_for || '(missing)') + ' / ' + S(inp.wants_to_be_known_for || '(missing)'));

return [{ json: Object.assign({}, req, { attempt_number: attempt, prompt_text: prompt_text }) }];

